  ('fire-eq-tech-moex-01722', 'fire-eq-tech', 'fire-eq-tech-moex-105-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '居室內可燃物量因燃燒而逐漸減少其重量之速度，謂之燃燒速度（R，單位kg/min）。當居室為混凝土造 時，可以採用國外經驗公式R=(5.5~6.0)×A× H計算燃燒速度，下列敘述何者正確？', '["A為居室面積（m2），H為天花板高度（m）", "A為居室面積（m2），H為開口高度（m）", "A為開口面積（m2），H為天花板高度（m）", "A為開口面積（m2），H為開口高度（m）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "27f1bee69e57", "answer_pdf_sha1": "d491cc8ab28a", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
